const parts = msg.topic.split('/');
const serial = parts[3];
const zone = parts[1];
const isOnline = msg.payload.toString().trim() === '1';

const key = 'online_' + serial;
const wasOnline = context.get(key);
context.set(key, isOnline);

// Went offline
if (!isOnline && wasOnline !== false) {
    const ts = new Date().toISOString();
    return [
        {
            payload: {
                severity: 'critical',
                condition: 'Device offline (LWT)',
                emailNeeded: true,
                serial, zone, ts,
                subject: `[MPPT CRITICAL] ${serial} — Device offline`,
                body: `Device ${serial} (zone: ${zone}) has gone offline.\nLWT received at ${ts}.`
            }
        },
        null
    ];
}

// Came back online (was previously offline)
if (isOnline && wasOnline === false) {
    const ts = new Date().toISOString();
    node.log(`${serial} is back online`);
    return [
        null,
        {
            payload: {
                severity: 'info',
                condition: 'Device back online',
                emailNeeded: false,
                serial, zone, ts,
                subject: `[MPPT INFO] ${serial} — Device back online`,
                body: `Device ${serial} (zone: ${zone}) is back online at ${ts}.`
            }
        }
    ];
}

return null;

const parts = msg.topic.split('/');
if (parts.length < 5) return null;
msg.zone = parts[1];
msg.gateway_id = parts[2];
msg.serial = parts[3];
const p = msg.payload || {};
msg.gen = p.general || {};
msg.bat = p.battery || {};
msg.load = p.load || {};
msg.pv = p.pv || {};
msg.led = p.led || {};
msg.faults = p.faults || {};
return msg;

const bat = msg.bat,
    load = msg.load,
    faults = msg.faults,
    serial = msg.serial,
    zone = msg.zone,
    ts = msg.gen.timestamp || new Date().toISOString();

const checks = [
    {
        severity: 'warning',
        condition: `Battery SOC low (${bat.soc_pct}%)`,
        email: false,
        active: bat.soc_pct >= 10 && bat.soc_pct < 20
    },
    {
        severity: 'critical',
        condition: `Battery SOC critical (${bat.soc_pct}%)`,
        email: true,
        active: bat.soc_pct < 10
    },
    {
        severity: 'critical',
        condition: 'LVD active',
        email: true,
        active: !!(faults.lvd_active || load.lvd_active)
    },
    {
        severity: 'critical',
        condition: 'Battery Over Voltage',
        email: true,
        active: !!faults.battery_over_voltage
    },
    {
        severity: 'critical',
        condition: 'Battery Over-Discharge',
        email: true,
        active: !!faults.over_discharge_current
    },
    {
        severity: 'critical',
        condition: 'Battery Over Temperature',
        email: true,
        active: !!faults.battery_over_temp
    },
    {
        severity: 'critical',
        condition: 'Battery Under Temperature',
        email: true,
        active: !!faults.battery_under_temp
    }
];

// Build one message per active alert — downstream nodes receive them individually
const msgs = [];
for (const c of checks) {
    if (!c.active) continue;
    msgs.push({
        payload: {
            severity: c.severity,
            condition: c.condition,
            emailNeeded: c.email,
            serial,
            zone,
            ts,
            subject: `[MPPT ${c.severity.toUpperCase()}] ${serial} - ${c.condition}`,
            body: `Device: ${serial}\nZone: ${zone}\nCondition: ${c.condition}\nTimestamp: ${ts}`
        }
    });
}

if (msgs.length === 0) return null;

const emailMsgs = msgs.filter(m => m.payload.emailNeeded);
return [
    emailMsgs.length ? emailMsgs : null,
    msgs
];

// Guard: payload must be a single alert object with subject/body
if (!msg.payload || typeof msg.payload !== 'object') {
    node.warn('Format email: unexpected payload type: ' + typeof msg.payload);
    return null;
}
if (!msg.payload.subject || !msg.payload.body) {
    node.warn('Format email: missing subject or body - ' + JSON.stringify(msg.payload));
    return null;
}
msg.topic = msg.payload.subject;
msg.payload = msg.payload.body;
return msg;

const tags = {
    zone: msg.zone,
    gateway_id: msg.gateway_id,
    serial: msg.serial,
};
const fields = {
    voltage_v: msg.bat.voltage_v,
    soc_pct: msg.bat.soc_pct,
    charge_current_a: msg.bat.charge_current_a,
    charge_power_w: msg.bat.charge_power_w,
    charge_mode: msg.bat.charge_mode,
    is_night: msg.bat.is_night ? 1 : 0,
    energy_in_daily_wh: msg.bat.energy_in_daily_wh,
    load_on: msg.load.load_on ? 1 : 0,
    lvd_active: (msg.load.lvd_active || msg.faults.lvd_active) ? 1 : 0,
    load_current_a: msg.load.current_a,
    load_power_w: msg.load.power_w,
    pv_voltage_v: msg.pv.voltage_v,
    internal_temp_c: msg.gen.internal_temp_c,
    external_temp_c: msg.gen.external_temp_c,
    led_voltage_v: msg.led.voltage_v || 0,
    led_current_a: msg.led.current_a || 0
};
msg.payload = [fields, tags];
return msg;

const f = msg.faults,
    load = msg.load;
const any = !!(f.battery_over_voltage || f.pv_over_voltage || f.charge_over_current || f.lvd_active || f.over_discharge_current || f.load_over_current || f.battery_over_temp || f.battery_under_temp || load.lvd_active || load.over_current);
const tags = {
    zone: msg.zone,
    gateway_id: msg.gateway_id,
    serial: msg.serial,
};
const fields = {
    battery_over_voltage: f.battery_over_voltage ? 1 : 0,
    pv_over_voltage: f.pv_over_voltage ? 1 : 0,
    charge_over_current: f.charge_over_current ? 1 : 0,
    lvd_active: (f.lvd_active || load.lvd_active) ? 1 : 0,
    over_discharge_current: f.over_discharge_current ? 1 : 0,
    load_over_current: (f.load_over_current || load.over_current) ? 1 : 0,
    battery_over_temp: f.battery_over_temp ? 1 : 0,
    battery_under_temp: f.battery_under_temp ? 1 : 0,
    any_fault: any ? 1 : 0
};
msg.payload = [fields, tags];
return msg;

const parts = msg.topic.split('/');
if (parts.length < 5) return null;

const gateway = parts[2];
const serial = parts[3];
const zone = parts[1];

const dl = msg.payload?.datalogger;
if (!dl) return null;

const num = (v) => (typeof v === "number" ? v : 0);

const summaryOut = [];
const dailyOut = [];
const monthlyOut = [];

summaryOut.push({
  measurement: "datalogger_summary",
  payload: [
    {
      recorded_days: num(dl.recorded_days),
      days_with_lvd: num(dl.days_with_lvd),
      months_without_full_charge: num(dl.months_without_full_charge),
      avg_morning_soc_pct: num(dl.avg_morning_soc_pct),
      total_ah_charge: num(dl.total_ah_charge),
      total_ah_load: num(dl.total_ah_load)
    },
    {
      serial,
      gateway_id: gateway,
      zone
    }
  ]
});

if (Array.isArray(dl.daily)) {
  dl.daily.forEach((d, i) => {
    dailyOut.push({
      measurement: "datalogger_daily",
      payload: [
        {
          day_num: num(d.day),
          vbat_min_v: num(d.vbat_min_v),
          vbat_max_v: num(d.vbat_max_v),
          vpv_min_v: num(d.vpv_min_v),
          vpv_max_v: num(d.vpv_max_v),
          ah_charge: num(d.ah_charge),
          ah_load: num(d.ah_load),
          soc_pct: num(d.soc_pct),
          ext_temp_max_c: num(d.ext_temp_max_c),
          ext_temp_min_c: num(d.ext_temp_min_c),
          nightlength_min: num(d.nightlength_min),
          il_max_a: num(d.il_max_a),
          ipv_max_a: num(d.ipv_max_a)
        },
        {
          serial,
          gateway_id: gateway,
          zone,
          day_index: String(i + 1)
        }
      ]
    });
  });
}

if (Array.isArray(dl.monthly)) {
  dl.monthly.forEach((m, i) => {
    monthlyOut.push({
      measurement: "datalogger_monthly",
      payload: [
        {
          month_num: num(m.month),
          vbat_min_v: num(m.vbat_min_v),
          vbat_max_v: num(m.vbat_max_v),
          vpv_min_v: num(m.vpv_min_v),
          vpv_max_v: num(m.vpv_max_v),
          ah_charge: num(m.ah_charge),
          ah_load: num(m.ah_load),
          ipv_max_a: num(m.ipv_max_a),
          il_max_a: num(m.il_max_a),
          soc_pct: num(m.soc_pct),
          ext_temp_max_c: num(m.ext_temp_max_c),
          ext_temp_min_c: num(m.ext_temp_min_c),
          nightlength_min: num(m.nightlength_min)
        },
        {
          serial,
          gateway_id: gateway,
          zone,
          month_index: String(i + 1)
        }
      ]
    });
  });
}

return [
  summaryOut.length ? summaryOut : null,
  dailyOut.length ? dailyOut : null,
  monthlyOut.length ? monthlyOut : null
];
